import { useEffect, useRef } from 'react';
import { createChart } from 'lightweight-charts';

function BaselineChartBTC({ sparklinedata }) {
  const chartContainerRef = useRef(null);
  const chartRef = useRef(null);
  const seriesRef = useRef(null);

  useEffect(() => {
    if (!chartContainerRef.current) return;

    const chart = createChart(chartContainerRef.current, {
      width: 900,
      height: 400,

      layout: {
        textColor: '#cbd5e1',
        background: { type: 'solid', color: '#0b0f19' },
      },

      grid: {
        vertLines: { visible: false },
        horzLines: { visible: false },
      },

      rightPriceScale: { borderVisible: false, visible: false },

      timeScale: {
        borderVisible: false,
        visible: false,
        rightOffset: 6,
        barSpacing: 8,
        minBarSpacing: 2,
        fixLeftEdge: true,
        fixRightEdge: true,
      },

      crosshair: {
        mode: 0,
        vertLine: { visible: false, labelVisible: false },
        horzLine: { visible: false, labelVisible: false },
      },

      watermark: { visible: false },

      handleScroll: {
        mouseWheel: true,
        pressedMouseMove: true,
        horzTouchDrag: true,
        vertTouchDrag: false,
      },

      handleScale: {
        mouseWheel: true,
        pinch: true,
        axisPressedMouseMove: { time: true, price: true },
      },

      localization: { locale: 'en-GB' },
    });

    const series = chart.addAreaSeries();

    chartRef.current = chart;
    seriesRef.current = series;

    chart.timeScale().fitContent();

    return () => {
      chart.remove();
      chartRef.current = null;
      seriesRef.current = null;
    };
  }, []);

  useEffect(() => {
    if (!seriesRef.current || !Array.isArray(sparklinedata)) return;

    const res = sparklinedata.map(([time, value]) => ({
      time: Math.floor(time / 1000),
      value: Number(value),
    }));

    seriesRef.current.setData(res);
    chartRef.current?.timeScale().fitContent();
  }, [sparklinedata]);

  return <div ref={chartContainerRef} />;
}

export default BaselineChartBTC;
